(9, 'Follow-up Sequence – Day 10 (Last Touch)', '{Letzte Nachricht von KryptoxPay|Dies ist meine letzte E-Mail, {{name}}|Abschließende Information für Sie|Auf Wiedersehen – und eine letzte Chance}', '<!DOCTYPE html>\r\n<html lang=\"de\">\r\n<head>\r\n<meta charset=\"UTF-8\">\r\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\r\n<meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\">\r\n<title>KryptoxPay – Letzte Nachricht</title>\r\n<style>\r\n  body,table,td,a{-webkit-text-size-adjust:100%;-ms-text-size-adjust:100%}\r\n  body{margin:0;padding:0;background:#f2f4f7;font-family:\'Helvetica Neue\',Helvetica,Arial,sans-serif}\r\n  table{border-collapse:collapse}\r\n  .wrapper{width:100%;background:#f2f4f7;padding:30px 0}\r\n  .card{max-width:600px;margin:0 auto;background:#ffffff;border-radius:10px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.08)}\r\n  .hd{background:#1a1a2e;padding:32px 40px;text-align:center}\r\n  .hd-logo{font-size:24px;font-weight:700;color:#ffffff;text-decoration:none;display:block}\r\n  .hd-logo span{color:#f0a500}\r\n  .hd-tag{margin:6px 0 0;font-size:11px;color:#8888aa;letter-spacing:1px;text-transform:uppercase}\r\n  .bd{padding:36px 40px;color:#374151;font-size:15px;line-height:1.8}\r\n  .bd h2{margin:0 0 16px;font-size:20px;color:#1a1a2e;font-weight:700}\r\n  .bd p{margin:0 0 14px}\r\n  .divider{height:1px;background:#e8edf2;margin:20px 0}\r\n  .cta{text-align:center;margin:26px 0}\r\n  .btn{display:inline-block;background:#1a1a2e;color:#f0a500 !important;padding:14px 36px;border-radius:6px;font-size:15px;font-weight:700;text-decoration:none;border:2px solid #f0a500}\r\n  .ps{background:#fffbeb;border:1px solid #fde68a;border-radius:6px;padding:16px 20px;margin-top:20px}\r\n  .ps p{margin:0;font-size:13px;color:#92400e}\r\n  .ft{background:#f8f9fb;padding:20px 40px;text-align:center;font-size:12px;color:#6b7280}\r\n  .ft a{color:#6b7280}\r\n  @media only screen and (max-width:620px){\r\n    .card{border-radius:0!important}\r\n    .bd,.hd,.ft{padding:24px 20px!important}\r\n  }\r\n</style>\r\n</head>\r\n<body>\r\n<div class=\"wrapper\">\r\n<table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\r\n<tr><td align=\"center\">\r\n<table class=\"card\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\">\r\n\r\n  <tr><td class=\"hd\">\r\n    <a href=\"https://kryptoxpay.co.uk\" class=\"hd-logo\">Kryptox<span>Pay</span></a>\r\n    <p class=\"hd-tag\">Asset Recovery &amp; Digital Finance</p>\r\n  </td></tr>\r\n\r\n  <tr><td class=\"bd\">\r\n    <h2>Liebe/r {{name}},</h2>\r\n\r\n    <p>ich {werde mich nach dieser Nachricht|möchte nach dieser E-Mail} nicht mehr bei\r\n    Ihnen {melden|in Verbindung setzen} – {das verspreche ich Ihnen|Sie haben mein Wort}.</p>\r\n\r\n    <p>Aber {bevor ich das tue|bevor ich mich verabschiede}, {möchte ich|wollte ich}\r\n    {noch einmal|ein letztes Mal} klar sein:</p>\r\n\r\n    {{#if scam_platform}}\r\n    <p>Wenn Sie {tatsächlich Kapital durch|wirklich Verluste über}\r\n    <strong>{{scam_platform}}</strong> {erlitten haben|verloren haben},\r\n    dann {haben Sie|stehen Ihnen} {möglicherweise rechtliche und praktische Möglichkeiten\r\n    offen|Optionen zur Verfügung}, die Sie {noch nicht kennen|bisher nicht in Betracht\r\n    gezogen haben}.</p>\r\n    {{else}}\r\n    <p>Wenn Sie sich {jemals fragen|eines Tages überlegen}, ob Ihre digitalen Anlagen\r\n    {sicher sind|optimal verwaltet werden} – oder ob jemand Ihren Fall\r\n    {kostenlos prüfen|unverbindlich analysieren} kann –\r\n    dann {wissen Sie, wo Sie uns finden|sind wir für Sie da}.</p>\r\n    {{/if}}\r\n\r\n    <div class=\"cta\">\r\n      <a href=\"https://kryptoxpay.co.uk?utm_source=email&amp;utm_campaign=day10&amp;utm_medium=cta\" class=\"btn\">\r\n        {Letzte Chance: Jetzt anfragen|Noch heute handeln|Kostenlose Prüfung – letzter Aufruf}\r\n      </a>\r\n    </div>\r\n\r\n    <div class=\"divider\"></div>\r\n\r\n    <div class=\"ps\">\r\n      <p><strong>P.S.</strong> {Falls Sie sich doch noch entscheiden, uns zu kontaktieren –\r\n      wir löschen Ihre Daten nach dieser letzten Nachricht nicht sofort. Sie können uns\r\n      jederzeit unter info@kryptoxpay.co.uk erreichen.|\r\n      Sie können uns jederzeit per E-Mail an info@kryptoxpay.co.uk kontaktieren,\r\n      auch wenn Sie diese Serie nicht weiterverfolgen möchten.}</p>\r\n    </div>\r\n\r\n    <p style=\"margin-top:20px\">Mit {freundlichen|herzlichen} Grüßen,<br>\r\n    <strong style=\"color:#1a1a2e\">{{sender_name}}</strong><br>\r\n    KryptoxPay – Asset Recovery</p>\r\n  </td></tr>\r\n\r\n  <tr><td class=\"ft\">\r\n    <p>KryptoxPay Ltd &nbsp;&middot;&nbsp; <a href=\"https://kryptoxpay.co.uk\">kryptoxpay.co.uk</a></p>\r\n    <p><a href=\"{{unsubscribe_url}}\">Abmelden</a> &nbsp;&middot;&nbsp;\r\n       <a href=\"https://kryptoxpay.co.uk/datenschutz\">Datenschutz</a> &nbsp;&middot;&nbsp;\r\n       <a href=\"https://kryptoxpay.co.uk/impressum\">Impressum</a></p>\r\n    <p>Dies ist die letzte E-Mail dieser Serie. Sie erhalten danach keine weiteren Nachrichten.</p>\r\n    {{open_tracker}}\r\n  </td></tr>\r\n\r\n</table>\r\n</td></tr>\r\n</table>\r\n</div>\r\n</body>\r\n</html>', 'Liebe/r {{name}},\r\n\r\nich {werde mich nach dieser Nachricht|möchte nach dieser E-Mail} nicht mehr bei\r\nIhnen {melden|in Verbindung setzen} – {das verspreche ich Ihnen|Sie haben mein Wort}.\r\n\r\nAber {bevor ich das tue|bevor ich mich verabschiede}, {möchte ich|wollte ich}\r\n{noch einmal|ein letztes Mal} klar sein:\r\n\r\n{{#if scam_platform}}\r\nWenn Sie {tatsächlich Kapital durch|wirklich Verluste über} {{scam_platform}}\r\n{erlitten haben|verloren haben}, dann {haben Sie|stehen Ihnen}\r\n{möglicherweise rechtliche und praktische Möglichkeiten offen|Optionen zur Verfügung},\r\ndie Sie {noch nicht kennen|bisher nicht in Betracht gezogen haben}.\r\n{{else}}\r\nWenn Sie sich {jemals fragen|eines Tages überlegen}, ob Ihre digitalen Anlagen\r\n{sicher sind|optimal verwaltet werden} – {wissen Sie, wo Sie uns finden|sind wir für Sie da}.\r\n{{/if}}\r\n\r\nP.S. Sie können uns jederzeit unter info@kryptoxpay.co.uk erreichen.\r\n\r\nMit {freundlichen|herzlichen} Grüßen,\r\n{{sender_name}}\r\nKryptoxPay – Asset Recovery\r\nhttps://kryptoxpay.co.uk\r\n\r\n---\r\nDies ist die letzte E-Mail dieser Serie. Sie erhalten danach keine weiteren Nachrichten.\r\nAbmelden: {{unsubscribe_url}}\r\nDatenschutz: https://kryptoxpay.co.uk/datenschutz', '2026-03-25 18:29:57'),
(10, 'Rotation – Neutral / Safe (Spintax)', '{Kurze Frage zu Ihrer Erfahrung|Kurze Rückfrage|Allgemeine Frage zu digitalen Themen}', '<!DOCTYPE html>\n<html lang=\"de\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<title>{{company_name}}</title>\n<style>\n  body{margin:0;padding:0;background:#f2f4f7;font-family:Arial,Helvetica,sans-serif}\n  .wrap{max-width:600px;margin:24px auto;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.07)}\n  .hdr{background:#0d2744;padding:24px 32px;text-align:center}\n  .hdr-logo{color:#f0a500;font-size:20px;font-weight:700;text-decoration:none}\n  .body{padding:32px;color:#374151;font-size:15px;line-height:1.8}\n  .body p{margin:0 0 14px}\n  .cta{text-align:center;margin:24px 0}\n  .cta a{display:inline-block;background:#f0a500;color:#fff!important;padding:12px 32px;border-radius:6px;font-weight:700;text-decoration:none;font-size:15px}\n  .foot{background:#f8fafc;padding:18px 32px;border-top:1px solid #e8edf2;font-size:12px;color:#9ca3af;text-align:center}\n  .foot a{color:#9ca3af}\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <div class=\"hdr\"><span class=\"hdr-logo\">{{company_name}}</span></div>\n  <div class=\"body\">\n    <p>{Guten Tag|Hallo} {{name}},</p>\n    <p>\n      {ich melde mich kurz|ich wollte mich kurz melden},\n      {da es aktuell vermehrt Themen rund um digitale Investitionen gibt|weil derzeit viele Fragen zu Online-Themen auftreten}.\n    </p>\n    <p>\n      {Möglicherweise hatten Sie bereits Berührungspunkte damit|Eventuell ist Ihnen das Thema bekannt}.\n    </p>\n    <p>\n      {Wir stellen dazu einige Informationen bereit|Wir bieten hierzu eine Übersicht},\n      {die bei der Einordnung helfen kann|zur besseren Orientierung}.\n    </p>\n    <div class=\"cta\">\n      <a href=\"{{site_url}}\">{Weitere Informationen|Zur Website|Mehr erfahren}</a>\n    </div>\n    <p>\n      {Falls nicht relevant, bitte ignorieren|Wenn das nicht passt, einfach ignorieren}.\n    </p>\n    <p>\n      {Viele Grüße|Beste Grüße}<br>\n      {{sender_name}}\n    </p>\n  </div>\n  <div class=\"foot\">\n    <p><a href=\"{{unsubscribe_url}}\">Abmelden</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/datenschutz\">Datenschutz</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/impressum\">Impressum</a></p>\n    <p>{{company_name}}</p>\n    {{open_tracker}}\n  </div>\n</div>\n</body>\n</html>', '{Guten Tag|Hallo} {{name}},\n\n{ich melde mich kurz|ich wollte mich kurz melden}, {da es aktuell vermehrt Themen rund um digitale Investitionen gibt|weil derzeit viele Fragen zu Online-Themen auftreten}.\n\n{Möglicherweise hatten Sie bereits Berührungspunkte damit|Eventuell ist Ihnen das Thema bekannt}.\n\n{Wir stellen dazu einige Informationen bereit|Wir bieten hierzu eine Übersicht}, {die bei der Einordnung helfen kann|zur besseren Orientierung}.\n\n{Weitere Informationen|Zur Website}: {{site_url}}\n\n{Falls nicht relevant, bitte ignorieren|Wenn das nicht passt, einfach ignorieren}.\n\n{Viele Grüße|Beste Grüße}\n{{sender_name}}\n{{company_name}}\n\nAbmelden: {{unsubscribe_url}}', '2026-03-25 18:54:03');
INSERT INTO `mailing_templates` (`id`, `name`, `subject`, `body_html`, `body_text`, `created_at`) VALUES
(11, 'Rotation – Soft Question Style (Spintax)', '{Ist das aktuell relevant für Sie?|Passt das aktuell bei Ihnen?|Kurze Nachfrage}', '<!DOCTYPE html>\n<html lang=\"de\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<title>{{company_name}}</title>\n<style>\n  body{margin:0;padding:0;background:#f2f4f7;font-family:Arial,Helvetica,sans-serif}\n  .wrap{max-width:600px;margin:24px auto;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.07)}\n  .hdr{background:#0d2744;padding:24px 32px;text-align:center}\n  .hdr-logo{color:#f0a500;font-size:20px;font-weight:700;text-decoration:none}\n  .body{padding:32px;color:#374151;font-size:15px;line-height:1.8}\n  .body p{margin:0 0 14px}\n  .cta{text-align:center;margin:24px 0}\n  .cta a{display:inline-block;background:#f0a500;color:#fff!important;padding:12px 32px;border-radius:6px;font-weight:700;text-decoration:none;font-size:15px}\n  .foot{background:#f8fafc;padding:18px 32px;border-top:1px solid #e8edf2;font-size:12px;color:#9ca3af;text-align:center}\n  .foot a{color:#9ca3af}\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <div class=\"hdr\"><span class=\"hdr-logo\">{{company_name}}</span></div>\n  <div class=\"body\">\n    <p>Guten Tag {{name}},</p>\n    <p>\n      {ich wollte kurz nachfragen|kurze Rückfrage},\n      {ob das Thema digitale Investitionen für Sie aktuell relevant ist|ob Sie sich aktuell noch mit solchen Themen beschäftigen}.\n    </p>\n    <p>\n      {Falls ja, habe ich hier eine kleine Übersicht|Falls Interesse besteht, finden Sie hier weitere Infos}:\n    </p>\n    <div class=\"cta\">\n      <a href=\"{{site_url}}\">{Details ansehen|Zur Übersicht|Mehr Informationen}</a>\n    </div>\n    <p>Falls nicht, können Sie diese Nachricht einfach ignorieren.</p>\n    <p>\n      Freundliche Grüße<br>\n      {{sender_name}}\n    </p>\n  </div>\n  <div class=\"foot\">\n    <p><a href=\"{{unsubscribe_url}}\">Abmelden</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/datenschutz\">Datenschutz</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/impressum\">Impressum</a></p>\n    <p>{{company_name}}</p>\n    {{open_tracker}}\n  </div>\n</div>\n</body>\n</html>', 'Guten Tag {{name}},\n\n{ich wollte kurz nachfragen|kurze Rückfrage}, {ob das Thema digitale Investitionen für Sie aktuell relevant ist|ob Sie sich aktuell noch mit solchen Themen beschäftigen}.\n\n{Falls ja, habe ich hier eine kleine Übersicht|Falls Interesse besteht, finden Sie hier weitere Infos}:\n{{site_url}}\n\nFalls nicht, können Sie diese Nachricht einfach ignorieren.\n\nFreundliche Grüße\n{{sender_name}}\n{{company_name}}\n\nAbmelden: {{unsubscribe_url}}', '2026-03-25 18:54:03'),
(12, 'Rotation – Brief Info Style (Spintax)', '{Ein kurzer Hinweis|Kurze Information für Sie|Kleine Rückmeldung}', '<!DOCTYPE html>\n<html lang=\"de\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n<title>{{company_name}}</title>\n<style>\n  body{margin:0;padding:0;background:#f2f4f7;font-family:Arial,Helvetica,sans-serif}\n  .wrap{max-width:600px;margin:24px auto;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 10px rgba(0,0,0,.07)}\n  .hdr{background:#0d2744;padding:24px 32px;text-align:center}\n  .hdr-logo{color:#f0a500;font-size:20px;font-weight:700;text-decoration:none}\n  .body{padding:32px;color:#374151;font-size:15px;line-height:1.8}\n  .body p{margin:0 0 14px}\n  .cta{text-align:center;margin:24px 0}\n  .cta a{display:inline-block;background:#f0a500;color:#fff!important;padding:12px 32px;border-radius:6px;font-weight:700;text-decoration:none;font-size:15px}\n  .foot{background:#f8fafc;padding:18px 32px;border-top:1px solid #e8edf2;font-size:12px;color:#9ca3af;text-align:center}\n  .foot a{color:#9ca3af}\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <div class=\"hdr\"><span class=\"hdr-logo\">{{company_name}}</span></div>\n  <div class=\"body\">\n    <p>{Guten Tag|Hallo} {{name}},</p>\n    <p>\n      {ich wollte Ihnen kurz eine Information zukommen lassen|kurze Info für Sie},\n      {die für Sie möglicherweise von Interesse ist|die aktuell viele beschäftigt}.\n    </p>\n    <p>\n      {Darf ich kurz nachfragen, ob das für Sie relevant ist?|Haben Sie dazu bereits eine Einschätzung?|Kurze Frage dazu}\n    </p>\n    <p>\n      {Bezug zu Ihren bisherigen Erfahrungen|Zu einem aktuellen Thema}:\n      {Wir bieten hierzu weiterführende Informationen an|Hier finden Sie alle relevanten Details}.\n    </p>\n    <div class=\"cta\">\n      <a href=\"{{site_url}}\">{Kurze Info ansehen|Mehr dazu erfahren|Zur Übersicht}</a>\n    </div>\n    <p>\n      {Viele Grüße|Mit freundlichen Grüßen}<br>\n      {{sender_name}}<br>\n      {{company_name}}\n    </p>\n  </div>\n  <div class=\"foot\">\n    <p><a href=\"{{unsubscribe_url}}\">Abmelden</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/datenschutz\">Datenschutz</a> &nbsp;|&nbsp;\n       <a href=\"{{site_url}}/impressum\">Impressum</a></p>\n    <p>{{company_name}}</p>\n    {{open_tracker}}\n  </div>\n</div>\n</body>\n</html>', '{Guten Tag|Hallo} {{name}},\n\n{ich wollte Ihnen kurz eine Information zukommen lassen|kurze Info für Sie}, {die für Sie möglicherweise von Interesse ist|die aktuell viele beschäftigt}.\n\n{Darf ich kurz nachfragen, ob das für Sie relevant ist?|Haben Sie dazu bereits eine Einschätzung?|Kurze Frage dazu}\n\n{Bezug zu Ihren bisherigen Erfahrungen|Zu einem aktuellen Thema}: {Wir bieten hierzu weiterführende Informationen an|Hier finden Sie alle relevanten Details}.\n\n{Kurze Info ansehen|Mehr dazu erfahren}: {{site_url}}\n\n{Viele Grüße|Mit freundlichen Grüßen}\n{{sender_name}}\n{{company_name}}\n\nAbmelden: {{unsubscribe_url}}', '2026-03-25 18:54:03');
